// Extrair dados do payload (suporta JSON direto ou url-encoded)
const input = $input.first().json;
let data;

if (input.body && input.body.payload) {
  data = typeof input.body.payload === 'string' ? JSON.parse(input.body.payload) : input.body.payload;
} else if (input.payload) {
  data = typeof input.payload === 'string' ? JSON.parse(input.payload) : input.payload;
} else {
  data = input;
}

return [{ json: data }];

// Recuperar dados das etapas anteriores
const payload = $('Extrair Dados').first().json;
const parceiroResult = $('Lookup Parceiro').first().json;
const splitConfigs = $('Buscar Split Config').first().json;

// Valor bruto da venda
const valorBruto = payload.payment.value;

// Montar array de splits com fixedValue (calculado sobre o bruto)
const splits = [];
const splitDetails = []; // para salvar no pedido_splits depois

// Verificar se parceiroResult é array ou objeto
const parceiro = Array.isArray(parceiroResult) ? parceiroResult[0] : parceiroResult;
const configs = Array.isArray(splitConfigs) ? splitConfigs : [splitConfigs];

// Splits fixos (sistemas, admin1, admin2)
for (const config of configs) {
  if (!config || !config.tipo || config.tipo === 'parceiro') continue;

  const valor = Math.round((valorBruto * config.percentual / 100) * 100) / 100;
  splits.push({
    walletId: config.wallet_id,
    fixedValue: valor
  });
  splitDetails.push({
    split_config_id: config.id,
    tipo: config.tipo,
    wallet_id: config.wallet_id,
    percentual_aplicado: config.percentual,
    valor_calculado: valor
  });
}

// Split do parceiro (se existe e tem utm_source)
let parceiroId = null;
if (parceiro && parceiro.wallet_id && payload.utm_source) {
  const comissao = parceiro.comissao_percent || 5;
  const valor = Math.round((valorBruto * comissao / 100) * 100) / 100;
  splits.push({
    walletId: parceiro.wallet_id,
    fixedValue: valor
  });
  splitDetails.push({
    split_config_id: null,
    tipo: 'parceiro',
    wallet_id: parceiro.wallet_id,
    percentual_aplicado: comissao,
    valor_calculado: valor
  });
  parceiroId = parceiro.id;
}

return [{
  json: {
    payload,
    splits,
    splitDetails,
    parceiroId,
    valorBruto
  }
}];

// Montar o body da cobrança com splits
const calcData = $('Calcular Splits').first().json;
const asaasCustomerId = $('Asaas Criar Cliente').first().json.id;
const payload = calcData.payload;
const splits = calcData.splits;

const paymentBody = {
  customer: asaasCustomerId,
  billingType: payload.payment.billingType || payload.billingType || 'CREDIT_CARD',
  value: payload.payment.value,
  dueDate: payload.payment.dueDate,
  description: payload.payment.description
};

// Adicionar dados de cartão se for CREDIT_CARD
if (paymentBody.billingType === 'CREDIT_CARD' && payload.payment.creditCard) {
  paymentBody.creditCard = payload.payment.creditCard;
  paymentBody.creditCardHolderInfo = {
    name: payload.customer.name,
    email: payload.customer.email,
    cpfCnpj: payload.customer.cpfCnpj,
    phone: payload.customer.phone,
    postalCode: payload.customer.postalCode,
    address: payload.customer.address,
    addressNumber: payload.customer.addressNumber,
    province: payload.customer.province
  };
  if (payload.payment.installmentCount > 1) {
    paymentBody.installmentCount = payload.payment.installmentCount;
    paymentBody.installmentValue = Math.round((payload.payment.value / payload.payment.installmentCount) * 100) / 100;
  }
}

// Adicionar splits (se existirem)
if (splits && splits.length > 0) {
  paymentBody.split = splits;
}

return [{ json: paymentBody }];

// Salvar pedido e splits no Supabase
const asaasPayment = $('Asaas Cobrar').first().json;
const asaasCustomer = $('Asaas Criar Cliente').first().json;
const calcData = $('Calcular Splits').first().json;
const leadData = $('Salvar Lead').first().json;
const lead = Array.isArray(leadData) ? leadData[0] : leadData;

// Verificar se pagamento foi bem-sucedido
const isSuccess = asaasPayment.id && !asaasPayment.errors;

if (!isSuccess) {
  return [{
    json: {
      success: false,
      error: asaasPayment.errors ? asaasPayment.errors[0].description : 'Erro ao processar pagamento'
    }
  }];
}

// Dados para Pix (se aplicável)
let pixData = {};
if (asaasPayment.billingType === 'PIX') {
  pixData = {
    pixQrCode: asaasPayment.encodedImage || '',
    pixCopyPaste: asaasPayment.payload || ''
  };
}

return [{
  json: {
    success: true,
    paymentId: asaasPayment.id,
    paymentStatus: asaasPayment.status,
    ...pixData,
    // Dados para salvar no Supabase (próximo nó)
    _pedido: {
      lead_id: lead.id || calcData.payload.lead_id,
      parceiro_id: calcData.parceiroId,
      asaas_customer_id: asaasCustomer.id,
      asaas_payment_id: asaasPayment.id,
      billing_type: asaasPayment.billingType,
      valor_bruto: calcData.valorBruto,
      plano: calcData.payload.produto,
      parcelas: calcData.payload.payment.installmentCount || 1,
      status: asaasPayment.status === 'CONFIRMED' ? 'aprovado' : 'pendente'
    },
    _splitDetails: calcData.splitDetails
  }
}];

// Salvar cada split individualmente
const resultado = $('Processar Resultado').first().json;
const pedidoData = $('Salvar Pedido').first().json;
const pedido = Array.isArray(pedidoData) ? pedidoData[0] : pedidoData;
const splitDetails = resultado._splitDetails || [];

if (!pedido || !pedido.id || splitDetails.length === 0) {
  return [{ json: resultado }];
}

// Preparar inserts de pedido_splits
const inserts = splitDetails.map(s => ({
  pedido_id: pedido.id,
  split_config_id: s.split_config_id,
  tipo: s.tipo,
  wallet_id: s.wallet_id,
  percentual_aplicado: s.percentual_aplicado,
  valor_calculado: s.valor_calculado,
  status: 'pendente'
}));

return [{ json: { ...resultado, _splitInserts: inserts } }];

// Responder ao frontend com resultado limpo
const resultado = $('Processar Resultado').first().json;

return [{
  json: {
    success: resultado.success,
    paymentId: resultado.paymentId || '',
    paymentStatus: resultado.paymentStatus || '',
    pixQrCode: resultado.pixQrCode || '',
    pixCopyPaste: resultado.pixCopyPaste || '',
    error: resultado.error || ''
  }
}];
